import{_ as e,c as t,o as r,a2 as a}from"./chunks/framework.DdOM6S6U.js";const p=JSON.parse('{"title":"System Reference","description":"","frontmatter":{"sidebarPos":1,"sidebarTitle":"System Reference"},"headers":[],"relativePath":"system-reference/index.md","filePath":"system-reference/index.md","lastUpdated":null}'),o={name:"system-reference/index.md"},d=a('<h1 id="system-reference" tabindex="-1">System Reference <a class="header-anchor" href="#system-reference" aria-label="Permalink to &quot;System Reference&quot;">​</a></h1><p>Modularity (Modularous) is a Laravel package that provides a modular admin panel powered by Vue.js, Vuetify, and Inertia. It uses the Repository pattern for data access, config-driven forms and tables, and a Hydrate system to transform module config into frontend schema.</p><h2 id="documentation-index" tabindex="-1">Documentation Index <a class="header-anchor" href="#documentation-index" aria-label="Permalink to &quot;Documentation Index&quot;">​</a></h2><table><thead><tr><th>Page</th><th>Description</th></tr></thead><tbody><tr><td><a href="./architecture">Architecture</a></td><td>System overview, request flow, schema flow, core classes</td></tr><tr><td><a href="./hydrates">Hydrates</a></td><td>Backend → frontend schema transformation (input types)</td></tr><tr><td><a href="./repositories">Repositories</a></td><td>Data access layer, lifecycle, Logic traits</td></tr><tr><td><a href="./backend">Backend</a></td><td>Controllers, Console commands, Entities, Services</td></tr><tr><td><a href="./frontend">Frontend</a></td><td>Vue structure, form/table flow, hooks, store</td></tr><tr><td><a href="./config">Config</a></td><td>Configuration layers (merges, defers, publishes)</td></tr><tr><td><a href="./modules">Modules</a></td><td>Module vs route activation, structure</td></tr><tr><td><a href="./api">API</a></td><td>Common patterns and use cases</td></tr><tr><td><a href="./pinia-migration">Pinia Migration</a></td><td>Vuex → Pinia migration path</td></tr><tr><td><a href="./console-conventions">Console Conventions</a></td><td>Command naming and signature rules</td></tr><tr><td><a href="./entities">Entities</a></td><td>Models, entity traits, enums</td></tr><tr><td><a href="./features">Features Pattern</a></td><td>Entity + Repository + Hydrate triple pattern</td></tr></tbody></table><h2 id="quick-reference" tabindex="-1">Quick Reference <a class="header-anchor" href="#quick-reference" aria-label="Permalink to &quot;Quick Reference&quot;">​</a></h2><p><strong>Key config keys</strong></p><ul><li><code>modularity.services.*</code> — services (currency_exchange, etc.)</li><li><code>modularity.roles</code> — role definitions</li><li><code>modularity.traits</code> — entity traits</li><li><code>modularity.paths</code> — base paths</li><li><code>modularity.currency_provider</code> — currency provider FQCN</li></ul><p><strong>Key commands</strong></p><ul><li><code>modularity:build</code> — rebuild Vue assets</li><li><code>modularity:route:enable</code> / <code>modularity:route:disable</code> — toggle routes</li><li><code>modularity:route:status</code> — list route status per module</li></ul><p><strong>Paths</strong></p><ul><li>Package source: <code>packages/modularous/src/</code></li><li>Vue source: <code>packages/modularous/vue/src/js/</code></li><li>Modules: <code>config(&#39;modules.paths.modules&#39;)</code> (default: <code>modules/</code>)</li></ul><h2 id="for-contributors" tabindex="-1">For Contributors <a class="header-anchor" href="#for-contributors" aria-label="Permalink to &quot;For Contributors&quot;">​</a></h2><p>See <a href="https://github.com/unusualify/modularity/blob/main/AGENTS.md" target="_blank" rel="noreferrer">AGENTS.md</a> for package development rules, patterns, and conventions.</p>',13),s=[d];function i(n,c,l,u,m,f){return r(),t("div",null,s)}const y=e(o,[["render",i]]);export{p as __pageData,y as default};
